// Velvet — noise blended with voronoi for soft organic texture
speed = 0.4

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// noise + voronoi = organic texture with cell edges
noise(2, 0.05)
  .blend(voronoi(4, 0.1, 0.6), 0.4)
  .modulateRotate(noise(0.5, 0.04), 0.04)
  .color(
    () => 0.7 + low() * 0.8,
    () => 0.3 + mid() * 1.0,
    () => 0.5 + high() * 0.9
  )
  .add(gradient(0.1).rotate(() => time * 0.015).saturate(1.5).color(0.2, 0.15, 0.3), 0.2)
  // very heavy feedback for dreamy softness
  .blend(src(o0).hue(() => 0.004 + amp() * 0.007).colorama(() => 0.002 + low() * 0.003), 0.87)
  .saturate(() => 1.1 + low() * 0.5)
  .contrast(() => 1.02 + low() * 0.08)
  .brightness(() => 0.03 + low() * 0.04)
  .out(o0)
